# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Secure allowlist of allowed commands
ALLOWED_COMMANDS = {
    'ls', 'pwd', 'echo', 'cat', 'grep', 'find', 'wc', 'head', 'tail',
    'date', 'whoami', 'id', 'uname', 'ps', 'df', 'free', 'uptime'
}

# Secure environment configuration
SECURE_ENV = {
    'PATH': '/usr/bin:/bin:/usr/sbin:/sbin',
    'HOME': '/tmp',
    'LANG': 'C',
    'LC_ALL': 'C'
}

class SecureRabbitMQConsumer:
    def __init__(self, connection_string: str, queue_name: str):
        self.connection_string = connection_string
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        """Establish secure RabbitMQ connection"""
        try:
            credentials = pika.PlainCredentials(
                os.getenv('RABBITMQ_USER', 'guest'),
                os.getenv('RABBITMQ_PASSWORD', 'guest')
            )
            parameters = pika.ConnectionParameters(
                host=os.getenv('RABBITMQ_HOST', 'localhost'),
                port=int(os.getenv('RABBITMQ_PORT', 5672)),
                credentials=credentials,
                heartbeat=600,
                blocked_connection_timeout=300
            )
            self.connection = pika.BlockingConnection(parameters)
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue=self.queue_name, durable=True)
            self.channel.basic_qos(prefetch_count=1)
        except Exception as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise
    
    def validate_command(self, command: str) -> bool:
        """Validate that command is in allowlist"""
        if not isinstance(command, str):
            return False
            
        # Split command into parts
        parts = command.strip().split()
        if not parts:
            return False
            
        # Check if first part (command) is in allowlist
        if parts[0] not in ALLOWED_COMMANDS:
            logger.warning(f"Command not in allowlist: {parts[0]}")
            return False
            
        # Additional security checks
        if any(part.startswith('-') for part in parts[1:]):
            logger.warning(f"Command contains potentially dangerous flags: {command}")
            return False
            
        return True
    
    def execute_command(self, command: str) -> Optional[str]:
        """Execute command securely"""
        try:
            # Validate command
            if not self.validate_command(command):
                logger.error(f"Invalid command rejected: {command}")
                return None
                
            # Execute with secure environment
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=30,
                env=SECURE_ENV
            )
            
            if result.returncode == 0:
                logger.info(f"Command executed successfully: {command}")
                return result.stdout
            else:
                logger.error(f"Command failed with return code {result.returncode}: {command}")
                return f"Error: {result.stderr}"
                
        except subprocess.TimeoutExpired:
            logger.error(f"Command timed out: {command}")
            return "Error: Command timed out"
        except Exception as e:
            logger.error(f"Failed to execute command {command}: {e}")
            return f"Error: {str(e)}"
    
    def process_message(self, ch, method, properties, body):
        """Process incoming message"""
        try:
            # Parse message
            message = json.loads(body.decode('utf-8'))
            command = message.get('command')
            
            if not command:
                logger.warning("Message missing command field")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
                return
                
            # Execute command
            output = self.execute_command(command)
            
            # Acknowledge message
            ch.basic_ack(delivery_tag=method.delivery_tag)
            
            logger.info(f"Processed command: {command}")
            
        except json.JSONDecodeError:
            logger.error("Invalid JSON in message")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
        except Exception as e:
            logger.error(f"Error processing message: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    
    def start_consuming(self):
        """Start consuming messages"""
        try:
            self.channel.basic_consume(
                queue=self.queue_name,
                on_message_callback=self.process_message
            )
            logger.info("Starting to consume messages...")
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Stopping consumer...")
            self.channel.stop_consuming()
            self.connection.close()
        except Exception as e:
            logger.error(f"Error in consumer: {e}")
            self.connection.close()

